{
  "name": "Gemini Stitch Studio",
  "description": "A multimodal creative playground where you can stitch together AI-generated text, images, audio, and video into a single cohesive story using the latest Gemini models.",
  "requestFramePermissions": [
    "camera",
    "microphone"
  ]
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum StitchType {
  TEXT = 'TEXT',
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO'
}

export interface StitchItem {
  id: string;
  type: StitchType;
  content: string; // Base64 for media, string for text
  prompt: string;
  timestamp: number;
  metadata?: {
    aspectRatio?: string;
    duration?: number;
    voiceName?: string;
  };
}

export interface GenerationState {
  isGenerating: boolean;
  progress: number;
  message: string;
  error?: string;
}

import { GoogleGenAI, Modality } from "@google/genai";
import { StitchType } from "../types";

export const decodeAudio = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const decodeAudioData = async (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {}

  static getInstance(): GeminiService {
    if (!this.instance) {
      this.instance = new GeminiService();
    }
    return this.instance;
  }

  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  async generateText(prompt: string): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "";
  }

  async generateImage(prompt: string): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: 'gemini-2.5-flash-image',
      contents: { parts: [{ text: prompt }] },
      config: {
        imageConfig: { aspectRatio: "16:9" }
      }
    });

    for (const part of response.candidates?.[0]?.content?.parts || []) {
      if (part.inlineData) {
        return `data:image/png;base64,${part.inlineData.data}`;
      }
    }
    throw new Error("Failed to generate image");
  }

  async generateTTS(prompt: string, voiceName: string = 'Kore'): Promise<string> {
    const ai = this.getAI();
    const response = await ai.models.generateContent({
      model: "gemini-2.5-flash-preview-tts",
      contents: [{ parts: [{ text: prompt }] }],
      config: {
        responseModalities: [Modality.AUDIO],
        speechConfig: {
          voiceConfig: {
            prebuiltVoiceConfig: { voiceName },
          },
        },
      },
    });

    const base64Audio = response.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
    if (!base64Audio) throw new Error("Audio generation failed");
    return base64Audio;
  }

  async generateVideo(prompt: string, onProgress?: (msg: string) => void): Promise<string> {
    const ai = this.getAI();

    // Check if user has selected key for Veo
    if (!(await (window as any).aistudio.hasSelectedApiKey())) {
       await (window as any).aistudio.openSelectKey();
    }

    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: prompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: '16:9'
      }
    });

    while (!operation.done) {
      onProgress?.("Brewing your video... this takes about a minute.");
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) throw new Error("Video download link not found");

    const videoRes = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await videoRes.blob();
    return URL.createObjectURL(blob);
  }
}

import React, { useState, useCallback, useRef } from 'react';
import { StitchType, StitchItem, GenerationState } from './types';
import { GeminiService, decodeAudio, decodeAudioData } from './services/gemini';
import { Sidebar } from './components/Sidebar';
import { Timeline } from './components/Timeline';
import { Canvas } from './components/Canvas';
import { GenerationForm } from './components/GenerationForm';

const App: React.FC = () => {
  const [stitches, setStitches] = useState<StitchItem[]>([]);
  const [activeStitchId, setActiveStitchId] = useState<string | null>(null);
  const [activeType, setActiveType] = useState<StitchType>(StitchType.TEXT);
  const [genState, setGenState] = useState<GenerationState>({
    isGenerating: false,
    progress: 0,
    message: ''
  });

  const gemini = GeminiService.getInstance();
  const audioContextRef = useRef<AudioContext | null>(null);

  const activeStitch = stitches.find(s => s.id === activeStitchId) || null;

  const handleGenerate = async (prompt: string, options?: any) => {
    setGenState({ isGenerating: true, progress: 10, message: 'Initiating request...' });

    try {
      let content = '';
      let metadata = {};

      switch (activeType) {
        case StitchType.TEXT:
          content = await gemini.generateText(prompt);
          break;
        case StitchType.IMAGE:
          content = await gemini.generateImage(prompt);
          break;
        case StitchType.AUDIO:
          const voice = options?.voice || 'Kore';
          content = await gemini.generateTTS(prompt, voice);
          metadata = { voiceName: voice };
          break;
        case StitchType.VIDEO:
          content = await gemini.generateVideo(prompt, (msg) => {
            setGenState(prev => ({ ...prev, message: msg }));
          });
          break;
      }

      const newItem: StitchItem = {
        id: crypto.randomUUID(),
        type: activeType,
        content,
        prompt,
        timestamp: Date.now(),
        metadata
      };

      setStitches(prev => [...prev, newItem]);
      setActiveStitchId(newItem.id);
      setGenState({ isGenerating: false, progress: 100, message: 'Done!' });
    } catch (error: any) {
      console.error(error);
      setGenState({ 
        isGenerating: false, 
        progress: 0, 
        message: 'Error generating content', 
        error: error.message || 'Unknown error occurred' 
      });
    }
  };

  const playAudio = async (base64: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') await ctx.resume();

    try {
      const decoded = decodeAudio(base64);
      const buffer = await decodeAudioData(decoded, ctx, 24000, 1);
      const source = ctx.createBufferSource();
      source.buffer = buffer;
      source.connect(ctx.destination);
      source.start();
    } catch (e) {
      console.error("Audio playback error", e);
    }
  };

  const removeStitch = (id: string) => {
    setStitches(prev => prev.filter(s => s.id !== id));
    if (activeStitchId === id) setActiveStitchId(null);
  };

  return (
    <div className="flex h-screen w-full bg-zinc-950 text-zinc-100 overflow-hidden font-sans">
      <Sidebar 
        activeType={activeType} 
        onSelectType={setActiveType} 
      />

      <main className="flex-1 flex flex-col relative overflow-hidden">
        {/* Header */}
        <header className="h-16 border-b border-zinc-800 flex items-center justify-between px-6 bg-zinc-950/80 backdrop-blur-md z-10">
          <div className="flex items-center gap-3">
            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center">
              <span className="text-xl font-bold">S</span>
            </div>
            <h1 className="text-lg font-semibold tracking-tight">Gemini Stitch Studio</h1>
          </div>
          <div className="flex items-center gap-4">
            <button 
              className="px-4 py-1.5 rounded-full bg-zinc-800 hover:bg-zinc-700 text-sm transition-colors border border-zinc-700"
              onClick={() => (window as any).aistudio.openSelectKey()}
            >
              Update API Key
            </button>
            <div className="text-xs text-zinc-500 font-mono">
              {stitches.length} items in project
            </div>
          </div>
        </header>

        {/* Workspace */}
        <div className="flex-1 flex overflow-hidden">
          <div className="flex-1 p-6 flex flex-col gap-6 overflow-hidden">
            <div className="flex-1 rounded-2xl border border-zinc-800 bg-zinc-900/40 relative overflow-hidden shadow-2xl">
              <Canvas 
                activeStitch={activeStitch} 
                onPlayAudio={playAudio}
                isGenerating={genState.isGenerating}
                genMessage={genState.message}
              />
            </div>

            <GenerationForm 
              type={activeType} 
              onGenerate={handleGenerate}
              isGenerating={genState.isGenerating}
            />
          </div>
        </div>

        {/* Timeline (Sticky Bottom) */}
        <Timeline 
          items={stitches} 
          activeId={activeStitchId} 
          onSelect={setActiveStitchId}
          onRemove={removeStitch}
        />
      </main>

      {/* Global Error Notification */}
      {genState.error && (
        <div className="fixed bottom-32 left-1/2 -translate-x-1/2 px-6 py-3 rounded-xl bg-red-950 border border-red-500/50 text-red-200 text-sm shadow-xl z-50 flex items-center gap-3 animate-bounce">
          <svg className="w-5 h-5 text-red-400" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
          {genState.error}
          <button onClick={() => setGenState(prev => ({ ...prev, error: undefined }))} className="ml-2 hover:text-white">✕</button>
        </div>
      )}
    </div>
  );
};

export default App;

