          <h4 className="text-xs font-mono text-zinc-500 mb-6 flex items-center gap-2">
            <span className="w-2 h-2 rounded-full bg-blue-500"></span> TEXT CONTENT
          </h4>
          <div className="prose prose-invert prose-indigo">
