             </svg>
          </div>
          <h3 className="text-xl font-bold mb-2">Voice Generated</h3>
          <p className="text-zinc-400 text-sm mb-6">Voice: {activeStitch.metadata?.voiceName || 'Kore'}</p>
          <button 
