               <svg className="animate-spin h-5 w-5 text-white" xmlns="http://www.w3.org/2000/svg" fill="none" viewBox="0 0 24 24"><circle className="opacity-25" cx="12" cy="12" r="10" stroke="currentColor" strokeWidth="4"></circle><path className="opacity-75" fill="currentColor" d="M4 12a8 8 0 018-8V0C5.373 0 0 5.373 0 12h4zm2 5.291A7.962 7.962 0 014 12H0c0 3.042 1.135 5.824 3 7.938l3-2.647z"></path></svg>
            ) : (
              <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24">
                <path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" />
              </svg>
            )}
          </button>
        </div>
        <div className="flex justify-between items-center px-2">
           <span className="text-[10px] text-zinc-600 font-mono">POWERED BY {type === StitchType.VIDEO ? 'VEO 3.1' : 'GEMINI 2.5/3'}</span>
           <span className="text-[10px] text-zinc-600">Press Enter to generate</span>
        </div>
      </div>
    </form>
  );
};

export enum StitchType {
  TEXT = 'TEXT',
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO'
}

export interface StitchBlock {
  id: string;
  name: string;
  type: StitchType;
  prompt: string;
  output: string;
  isGenerating: boolean;
  error?: string;
  model: string;
}

export interface ProjectState {
  blocks: StitchBlock[];
  variables: Record<string, string>;
}

import { GoogleGenAI, Modality } from "@google/genai";
import { StitchType } from "../types";

export const decodeAudio = (base64: string) => {
  const binaryString = atob(base64);
  const len = binaryString.length;
  const bytes = new Uint8Array(len);
  for (let i = 0; i < len; i++) {
    bytes[i] = binaryString.charCodeAt(i);
  }
  return bytes;
};

export const decodeAudioData = async (
  data: Uint8Array,
  ctx: AudioContext,
  sampleRate: number,
  numChannels: number,
): Promise<AudioBuffer> => {
  const dataInt16 = new Int16Array(data.buffer);
  const frameCount = dataInt16.length / numChannels;
  const buffer = ctx.createBuffer(numChannels, frameCount, sampleRate);

  for (let channel = 0; channel < numChannels; channel++) {
    const channelData = buffer.getChannelData(channel);
    for (let i = 0; i < frameCount; i++) {
      channelData[i] = dataInt16[i * numChannels + channel] / 32768.0;
    }
  }
  return buffer;
};

export class GeminiService {
  private static instance: GeminiService;

  private constructor() {}

  static getInstance(): GeminiService {
    if (!this.instance) {
      this.instance = new GeminiService();
    }
    return this.instance;
  }

  private getAI() {
    return new GoogleGenAI({ apiKey: process.env.API_KEY });
  }

  replaceVariables(prompt: string, variables: Record<string, string>): string {
    return prompt.replace(/\{\{(.*?)\}\}/g, (_, key) => {
      const trimmedKey = key.trim();
      return variables[trimmedKey] || `{{${trimmedKey}}}`;
    });
  }

  async generate(type: StitchType, prompt: string, model: string = 'gemini-3-flash-preview'): Promise<string> {
    const ai = this.getAI();

    switch (type) {
      case StitchType.TEXT:
        const textRes = await ai.models.generateContent({
          model: model,
          contents: prompt,
        });
        return textRes.text || "";

      case StitchType.IMAGE:
        const imgRes = await ai.models.generateContent({
          model: 'gemini-2.5-flash-image',
          contents: { parts: [{ text: prompt }] },
          config: { imageConfig: { aspectRatio: "16:9" } }
        });
        for (const part of imgRes.candidates?.[0]?.content?.parts || []) {
          if (part.inlineData) return `data:image/png;base64,${part.inlineData.data}`;
        }
        throw new Error("No image data returned");

      case StitchType.AUDIO:
        const audioRes = await ai.models.generateContent({
          model: "gemini-2.5-flash-preview-tts",
          contents: [{ parts: [{ text: prompt }] }],
          config: {
            responseModalities: [Modality.AUDIO],
            speechConfig: { voiceConfig: { prebuiltVoiceConfig: { voiceName: 'Kore' } } },
          },
        });
        const base64 = audioRes.candidates?.[0]?.content?.parts?.[0]?.inlineData?.data;
        if (!base64) throw new Error("Audio generation failed");
        return base64;

      case StitchType.VIDEO:
        if (!(await (window as any).aistudio.hasSelectedApiKey())) {
           await (window as any).aistudio.openSelectKey();
        }
        let op = await ai.models.generateVideos({
          model: 'veo-3.1-fast-generate-preview',
          prompt: prompt,
          config: { numberOfVideos: 1, resolution: '720p', aspectRatio: '16:9' }
        });
        while (!op.done) {
          await new Promise(r => setTimeout(r, 10000));
          op = await ai.operations.getVideosOperation({ operation: op });
        }
        const link = op.response?.generatedVideos?.[0]?.video?.uri;
        const videoRes = await fetch(`${link}&key=${process.env.API_KEY}`);
        const blob = await videoRes.blob();
        return URL.createObjectURL(blob);

      default:
        throw new Error("Unsupported type");
    }
  }
}

