import React, { useState, useCallback, useRef, useEffect } from 'react';
import { StitchType, StitchBlock } from './types';
import { GeminiService, decodeAudio, decodeAudioData } from './services/gemini';
import { Block } from './components/Block';

const App: React.FC = () => {
  const [blocks, setBlocks] = useState<StitchBlock[]>([
    {
      id: crypto.randomUUID(),
      name: 'Stitch 1',
      type: StitchType.TEXT,
      prompt: 'Write a short intro about a futuristic library.',
      output: '',
      isGenerating: false,
      model: 'gemini-3-flash-preview'
    }
  ]);
  const [variables, setVariables] = useState<Record<string, string>>({});

  const gemini = GeminiService.getInstance();
  const audioContextRef = useRef<AudioContext | null>(null);

  // Sync variables whenever blocks change
  useEffect(() => {
    const newVars: Record<string, string> = {};
    blocks.forEach(b => {
      if (b.output && b.type === StitchType.TEXT) {
        newVars[b.name] = b.output;
      }
    });
    setVariables(newVars);
  }, [blocks]);

  const addBlock = (type: StitchType = StitchType.TEXT) => {
    const newBlock: StitchBlock = {
      id: crypto.randomUUID(),
      name: `Stitch ${blocks.length + 1}`,
      type,
      prompt: '',
      output: '',
      isGenerating: false,
      model: 'gemini-3-flash-preview'
    };
    setBlocks([...blocks, newBlock]);
  };

  const updateBlock = (id: string, updates: Partial<StitchBlock>) => {
    setBlocks(blocks.map(b => b.id === id ? { ...b, ...updates } : b));
  };

  const deleteBlock = (id: string) => {
    setBlocks(blocks.filter(b => b.id !== id));
  };

  const runBlock = async (id: string) => {
    const block = blocks.find(b => b.id === id);
    if (!block) return;

    updateBlock(id, { isGenerating: true, error: undefined });

    try {
      const processedPrompt = gemini.replaceVariables(block.prompt, variables);
      const result = await gemini.generate(block.type, processedPrompt, block.model);
      updateBlock(id, { output: result, isGenerating: false });
    } catch (err: any) {
      updateBlock(id, { error: err.message || 'Generation failed', isGenerating: false });
    }
  };

  const playAudio = async (base64: string) => {
    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)({ sampleRate: 24000 });
    }
    const ctx = audioContextRef.current;
    if (ctx.state === 'suspended') await ctx.resume();
    const decoded = decodeAudio(base64);
    const buffer = await decodeAudioData(decoded, ctx, 24000, 1);
    const source = ctx.createBufferSource();
    source.buffer = buffer;
    source.connect(ctx.destination);
    source.start();
  };

  return (
    <div className="flex h-screen w-full bg-[#0d1117] text-zinc-100 font-sans overflow-hidden">
      {/* Sidebar - Variables Panel */}
      <aside className="w-64 border-r border-zinc-800 bg-[#0d1117] flex flex-col p-6 overflow-y-auto">
        <div className="mb-8">
          <h2 className="text-xs font-bold text-zinc-500 uppercase tracking-widest mb-4">Context Variables</h2>
          <div className="space-y-2">
            {Object.keys(variables).length === 0 ? (
              <p className="text-xs text-zinc-600 italic">No variables yet. Text block outputs appear here.</p>
            ) : (
              Object.entries(variables).map(([name, val]) => (
                <div key={name} className="p-3 bg-zinc-900/50 border border-zinc-800 rounded-lg group">
                  <div className="flex items-center justify-between mb-1">
                    <span className="text-[10px] font-mono text-blue-400 font-bold">{"{{" + name + "}}"}</span>
                    <button className="opacity-0 group-hover:opacity-100 transition-opacity text-zinc-500 hover:text-white" onClick={() => navigator.clipboard.writeText(`{{${name}}}`)}>
                      <svg className="w-3 h-3" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M8 16H6a2 2 0 01-2-2V6a2 2 0 012-2h8a2 2 0 012 2v2m-6 12h8a2 2 0 002-2v-8a2 2 0 00-2-2h-8a2 2 0 00-2 2v8a2 2 0 002 2z" /></svg>
                    </button>
                  </div>
                  <p className="text-[10px] text-zinc-500 line-clamp-2 leading-relaxed">{val}</p>
                </div>
              ))
            )}
          </div>
        </div>
      </aside>

      {/* Main Content */}
      <main className="flex-1 flex flex-col relative bg-[#090b10]">
        <header className="h-16 border-b border-zinc-800 flex items-center justify-between px-8 bg-[#0d1117]/80 backdrop-blur-md z-20">
          <div className="flex items-center gap-4">
            <div className="w-8 h-8 rounded-full bg-blue-600 flex items-center justify-center shadow-lg shadow-blue-500/20">
              <svg className="w-5 h-5 text-white" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M13 10V3L4 14h7v7l9-11h-7z" /></svg>
            </div>
            <h1 className="text-lg font-bold tracking-tight bg-gradient-to-r from-white to-zinc-500 bg-clip-text text-transparent">Gemini Stitch</h1>
          </div>
          <div className="flex items-center gap-3">
             <button 
               onClick={() => (window as any).aistudio.openSelectKey()}
               className="px-4 py-1.5 rounded-full bg-zinc-800 hover:bg-zinc-700 text-xs font-medium border border-zinc-700 transition-colors"
             >
               Manage Project Key
             </button>
          </div>
        </header>

        {/* Blocks Feed */}
        <div className="flex-1 overflow-y-auto p-8 max-w-4xl mx-auto w-full pb-32">
          {blocks.map((block) => (
            <Block 
              key={block.id} 
              block={block} 
              onUpdate={updateBlock} 
              onRun={runBlock} 
              onDelete={deleteBlock}
              onPlayAudio={playAudio}
            />
          ))}

          {/* Add Block Interface */}
          <div className="flex flex-col items-center gap-6 mt-12 py-12 border-2 border-dashed border-zinc-800 rounded-3xl group hover:border-blue-500/50 transition-all bg-zinc-900/10">
            <div className="text-zinc-500 text-sm font-medium group-hover:text-blue-400">Add a new stitch to your project</div>
            <div className="flex gap-4">
              {[StitchType.TEXT, StitchType.IMAGE, StitchType.VIDEO, StitchType.AUDIO].map(type => (
                <button
                  key={type}
                  onClick={() => addBlock(type)}
                  className="px-6 py-2 rounded-xl bg-zinc-800 hover:bg-zinc-700 border border-zinc-700 text-xs font-bold transition-all hover:scale-105 active:scale-95 flex items-center gap-2"
                >
                  <span className={`w-2 h-2 rounded-full ${
                    type === StitchType.TEXT ? 'bg-blue-500' :
                    type === StitchType.IMAGE ? 'bg-green-500' :
                    type === StitchType.VIDEO ? 'bg-purple-500' : 'bg-pink-500'
                  }`} />
                  {type}
                </button>
              ))}
            </div>
          </div>
        </div>

        {/* Footer controls */}
        <div className="absolute bottom-8 left-1/2 -translate-x-1/2 flex items-center gap-2 bg-zinc-900/90 backdrop-blur-xl border border-zinc-800 px-6 py-3 rounded-2xl shadow-2xl z-30">
           <span className="text-xs text-zinc-500 mr-4">{blocks.length} Stitches chained</span>
           <button 
             onClick={() => blocks.forEach(b => runBlock(b.id))}
             className="px-6 py-2 rounded-full bg-blue-600 hover:bg-blue-500 text-white text-xs font-bold shadow-lg shadow-blue-500/30 transition-all flex items-center gap-2"
           >
             <svg className="w-4 h-4" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M10 18a8 8 0 100-16 8 8 0 000 16zM9.555 7.168A1 1 0 008 8v4a1 1 0 001.555.832l3-2a1 1 0 000-1.664l-3-2z" clipRule="evenodd" /></svg>
             Run All Sequence
           </button>
        </div>
      </main>
    </div>
  );
};

export default App;

