export enum ShiftType {
  ACTIVE = 'Activa',
  PASSIVE = 'Pasiva',
  CONSULTATION = 'Consultorio',
  HOME_VISIT = 'Visita Domicilio'
}

export enum PaymentStatus {
  PAID = 'Pagado',
  PENDING = 'Pendiente'
}

export interface Transaction {
  id: string;
  institution: string;
  type: ShiftType;
  date: string;
  amount: number;
  status: PaymentStatus;
  notes?: string;
  duration?: number;
  location?: string;
}

