  };

  return (
    <div className="fixed inset-0 bg-white lg:bg-black/60 z-[100] flex items-end lg:items-center justify-center animate-in fade-in duration-300">
      <div className="bg-white w-full lg:max-w-xl h-[95vh] lg:h-auto lg:rounded-[3rem] shadow-2xl overflow-y-auto p-6 lg:p-10 flex flex-col animate-in slide-in-from-bottom duration-500">
        <header className="flex items-center justify-between mb-8">
          <button onClick={onClose} className="p-2 text-slate-400 hover:text-slate-900 transition-colors">
            <svg className="w-8 h-8" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M6 18L18 6M6 6l12 12" /></svg>
          </button>
          <h2 className="text-xl font-black text-slate-900">Registrar Guardia</h2>
          <div className="w-10"></div>
        </header>

        <form onSubmit={handleApply} className="space-y-8 flex-1">
          {/* Income Display */}
          <div className="space-y-2">
            <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Ingresos Brutos</label>
            <div className="bg-slate-50 p-6 lg:p-10 rounded-[2.5rem] border border-slate-100 flex items-center justify-center gap-2">
               <span className="text-4xl font-black text-blue-600">$</span>
               <input 
                 type="number" 
                 value={amount}
                 onChange={(e) => setAmount(e.target.value)}
                 className="bg-transparent text-5xl font-black text-slate-300 w-full focus:outline-none focus:text-slate-900 text-center"
                 placeholder="0.00"
               />
            </div>
            <p className="text-[10px] text-slate-400 font-bold text-center">Monto total antes de deducciones.</p>
          </div>

          <div className="space-y-6">
            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Fecha del turno</label>
              <div className="relative">
                <input 
                  type="date" 
                  value={date}
                  onChange={(e) => setDate(e.target.value)}
                  className="w-full bg-white border border-slate-200 rounded-[1.25rem] p-4 font-bold focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all" 
                />
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Institución médica</label>
              <div className="relative group">
                <input 
                  type="text" 
                  value={institution}
                  onChange={(e) => setInstitution(e.target.value)}
                  placeholder="Ej: Hospital Italiano..."
                  className="w-full bg-white border border-slate-200 rounded-[1.25rem] p-4 font-bold focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all pr-12" 
                />
                <button className="absolute right-4 top-1/2 -translate-y-1/2 text-blue-600">
                  <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="2" d="M12 9v3m0 0v3m0-3h3m-3 0H9m12 0a9 9 0 11-18 0 9 9 0 0118 0z" /></svg>
                </button>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Tipo de guardia</label>
              <div className="grid grid-cols-2 gap-4">
                <button 
                  type="button" 
                  onClick={() => setType(ShiftType.ACTIVE)}
                  className={`flex items-center justify-center gap-2 p-4 rounded-2xl border font-bold transition-all ${type === ShiftType.ACTIVE ? 'bg-blue-50 border-blue-600 text-blue-600 shadow-md shadow-blue-100' : 'bg-white border-slate-200 text-slate-400'}`}
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path fillRule="evenodd" d="M3.172 5.172a4 4 0 015.656 0L10 6.343l1.172-1.171a4 4 0 115.656 5.656L10 17.657l-6.828-6.829a4 4 0 010-5.656z" clipRule="evenodd" /></svg>
                  Activa
                </button>
                <button 
                  type="button" 
                  onClick={() => setType(ShiftType.PASSIVE)}
                  className={`flex items-center justify-center gap-2 p-4 rounded-2xl border font-bold transition-all ${type === ShiftType.PASSIVE ? 'bg-blue-50 border-blue-600 text-blue-600 shadow-md shadow-blue-100' : 'bg-white border-slate-200 text-slate-400'}`}
                >
                  <svg className="w-5 h-5" fill="currentColor" viewBox="0 0 20 20"><path d="M10.707 2.293a1 1 0 00-1.414 0l-7 7a1 1 0 001.414 1.414L4 10.414V17a2 2 0 002 2h2a2 2 0 002-2v-2a1 1 0 112 0v2a2 2 0 002 2h2a2 2 0 002-2v-6.586l.293.293a1 1 0 001.414-1.414l-7-7z" /></svg>
                  Pasiva
                </button>
              </div>
            </div>

            <div className="space-y-2">
              <label className="text-xs font-black text-slate-400 uppercase tracking-widest">Notas adicionales</label>
              <textarea 
                value={notes}
                onChange={(e) => setNotes(e.target.value)}
                placeholder="Detalles, pacientes, observaciones..."
                className="w-full bg-white border border-slate-200 rounded-[1.25rem] p-4 font-medium focus:outline-none focus:ring-2 focus:ring-blue-100 transition-all min-h-[120px] resize-none"
              />
            </div>
          </div>

          <button 
            type="submit"
            className="w-full bg-blue-600 text-white p-5 rounded-3xl font-black text-lg shadow-xl shadow-blue-200 hover:bg-blue-700 transition-all flex items-center justify-center gap-3 active:scale-95"
          >
            <svg className="w-6 h-6" fill="none" stroke="currentColor" viewBox="0 0 24 24"><path strokeLinecap="round" strokeLinejoin="round" strokeWidth="3" d="M5 13l4 4L19 7" /></svg>
            Confirmar y Guardar
          </button>
        </form>
      </div>
    </div>
  );
};

export enum ShiftType {
  ACTIVE = 'Activa',
  PASSIVE = 'Pasiva',
  CONSULTATION = 'Consultorio',
  HOME_VISIT = 'Visita Domicilio'
}

export enum PaymentStatus {
  PAID = 'Pagado',
  PENDING = 'Pendiente'
}

export interface Transaction {
  id: string;
  institution: string;
  type: ShiftType;
  date: string;
  amount: number;
  status: PaymentStatus;
  notes?: string;
  duration?: number;
  location?: string;
}

export interface FinancialStats {
  totalMonthly: number;
  trendPercentage: number;
  projection: number;
  recentActivity: Transaction[];
}

// Added StitchType and StitchBlock to fix import errors in creative components
export enum StitchType {
  TEXT = 'TEXT',
  IMAGE = 'IMAGE',
  VIDEO = 'VIDEO',
  AUDIO = 'AUDIO'
}

export interface StitchBlock {
  id: string;
  name: string;
  type: StitchType;
  prompt: string;
  isGenerating: boolean;
  output: string;
  error?: string;
}
